// ─── Character Select System ─────────────────────────────────────────────────
#define NUM_CHARS 6

const char *char_names[NUM_CHARS] = {
    "Programmer", "Chef", "Garda", "Builder", "Financier", "Teacher"
};
const uint16_t *char_sprites[NUM_CHARS] = {
    programmer, chef, guard, builder, financier, teacher
};
const Move *char_moves[NUM_CHARS] = {
    programmer_moves, chef_moves, garda_moves,
    builder_moves, financier_moves, teacher_moves
};

int char_status[NUM_CHARS]; // 0=free, 1=player, 2=AI
int player_team[3];
int ai_team[3];

void update_char_row(int row, int cursor)
{
    uint16_t fg;
    if      (char_status[row] == 1) fg = COL_GREEN;
    else if (char_status[row] == 2) fg = COL_RED;
    else if (row == cursor)         fg = COL_WHITE;
    else                            fg = COL_GRAY;

    if (row == cursor && char_status[row] == 0)
        printText(">", 0, 34 + row * 12, COL_WHITE, COL_BLACK);
    else
        printText(" ", 0, 34 + row * 12, COL_BLACK, COL_BLACK);

    printText(char_names[row], 8, 34 + row * 12, fg, COL_BLACK);
}

void update_preview_box(int cursor)
{
    int bx = 80, by = 30, bw = 46, bh = 58;
    if (char_status[cursor] == 0) {
        draw_rect_border(bx, by, bw, bh, COL_WHITE);
        draw_filled_rect(bx+1, by+1, bw-2, bh-2, COL_BLACK);
        putImage(bx+7, by+1, PLAYER_SPR_W, PLAYER_SPR_H, char_sprites[cursor], 0, 0);
    } else {
        draw_filled_rect(bx, by, bw, bh, COL_DARKGRAY);
        draw_rect_border(bx, by, bw, bh, COL_GRAY);
        if (char_status[cursor] == 1) {
            printText("YOUR", bx+5, by+22, COL_GREEN, COL_DARKGRAY);
            printText("PICK", bx+5, by+32, COL_GREEN, COL_DARKGRAY);
        } else {
            printText(" AI ", bx+5, by+22, COL_RED, COL_DARKGRAY);
            printText("PICK", bx+5, by+32, COL_RED, COL_DARKGRAY);
        }
    }
}

void draw_char_select_screen(int cursor)
{
    draw_filled_rect(0, 0, 128, 160, COL_BLACK);
    printTextX2("Pick", 2, 2, COL_YELLOW, COL_BLACK);
    printTextX2("Char!", 60, 2, COL_YELLOW, COL_BLACK);
    printText("^/v move  > pick", 0, 22, COL_GRAY, COL_BLACK);
    for (int i = 0; i < NUM_CHARS; i++) update_char_row(i, cursor);
    update_preview_box(cursor);
}

int ai_pick_random(void)
{
    int available[NUM_CHARS], count = 0;
    for (int i = 0; i < NUM_CHARS; i++)
        if (char_status[i] == 0) available[count++] = i;
    if (count == 0) return -1;
    return available[rand_range(0, count - 1)];
}

void character_select(void)
{
    for (int i = 0; i < NUM_CHARS; i++) char_status[i] = 0;
    int player_picks = 0, ai_picks = 0, cursor = 0;

    btn_down_just(); btn_up_just(); btn_left_just(); btn_right_just();
    draw_char_select_screen(cursor);

    while (player_picks < 3) {
        delay(80);
        int bu = btn_up_just();
        int bd = btn_down_just();
        int br = btn_right_just();
        btn_left_just();

        if (bd) {
            int old = cursor;
            cursor = (cursor + NUM_CHARS - 1) % NUM_CHARS;
            update_char_row(old, cursor);
            update_char_row(cursor, cursor);
            update_preview_box(cursor);
        }
        if (bu) {
            int old = cursor;
            cursor = (cursor + 1) % NUM_CHARS;
            update_char_row(old, cursor);
            update_char_row(cursor, cursor);
            update_preview_box(cursor);
        }
        if (br && char_status[cursor] == 0) {
            char_status[cursor] = 1;
            player_team[player_picks++] = cursor;
            update_char_row(cursor, cursor);
            update_preview_box(cursor);
            delay(400);
            if (ai_picks < 3) {
                delay(500);
                int ai_choice = ai_pick_random();
                if (ai_choice >= 0) {
                    char_status[ai_choice] = 2;
                    ai_team[ai_picks++] = ai_choice;
                    update_char_row(ai_choice, cursor);
                    if (ai_choice == cursor) update_preview_box(cursor);
                    delay(600);
                }
            }
        }
    }

    // Summary screen
    draw_filled_rect(0, 0, 128, 160, COL_BLACK);
    printTextX2("READY!", 18, 10, COL_YELLOW, COL_BLACK);
    printText("Your team:", 2, 45, COL_GREEN, COL_BLACK);
    for (int i = 0; i < 3; i++)
        printText(char_names[player_team[i]], 2, 55 + i * 10, COL_GREEN, COL_BLACK);
    printText("AI team:", 2, 92, COL_RED, COL_BLACK);
    for (int i = 0; i < 3; i++)
        printText(char_names[ai_team[i]], 2, 102 + i * 10, COL_RED, COL_BLACK);
    printText("Press > to fight!", 2, 148, COL_GRAY, COL_BLACK);

    btn_down_just(); btn_up_just(); btn_left_just(); btn_right_just();
    while (!btn_right_just() && !btn_down_just()) {
        delay(50); btn_up_just(); btn_left_just();
    }
}

// ─── Start Screen ─────────────────────────────────────────────────────────────
void draw_start_screen_full(void)
{
    draw_filled_rect(0, 0, 128, 160, COL_BLACK);
    printTextX2("9-5", 38, 20, COL_YELLOW, COL_BLACK);
    printTextX2("FIGHTS!", 18, 40, COL_WHITE, COL_BLACK);
    printText(" START  ", 30, 80, COL_GRAY, COL_BLACK);
    printText(" CREDITS", 30, 90, COL_GRAY, COL_BLACK);
    printText(" QUIT   ", 30, 100, COL_GRAY, COL_BLACK);
}

void update_start_screen(int old_select, int new_select)
{
    const char *labels[3] = {" START  ", " CREDITS", " QUIT   "};
    printText(labels[old_select], 30, 80 + old_select * 10, COL_GRAY,  COL_BLACK);
    printText(labels[new_select], 30, 80 + new_select * 10, COL_WHITE, COL_BLACK);
    printText(" ", 22, 80 + old_select * 10, COL_BLACK, COL_BLACK);
    printText(">", 22, 80 + new_select * 10, COL_WHITE, COL_BLACK);
}

void credits(void)
{
    draw_filled_rect(0, 0, 128, 160, COL_BLACK);
    delay(50);
    printTextX2("Developers", 0, 20, COL_YELLOW, COL_BLACK);
    printText("Georgin Jobin", 0, 80, COL_WHITE, COL_BLACK);
    printText("Jamie MB",      0, 90, COL_WHITE, COL_BLACK);
    printText("Joe Rafter",    0, 100, COL_WHITE, COL_BLACK);
    btn_down_just(); btn_up_just(); btn_left_just(); btn_right_just();
    while (1) {
        if (btn_down_just() || btn_left_just() || btn_right_just() || btn_up_just()) return;
    }
}

// ─── Battle drawing helpers ───────────────────────────────────────────────────

void draw_move_buttons(int selected, const Move *moves)
{
    char labels[3][6];
    for (int i = 0; i < 3; i++) {
        int j;
        for (j = 0; j < 5 && moves[i].name[j]; j++) labels[i][j] = moves[i].name[j];
        labels[i][j] = 0;
    }
    for (int i = 0; i < 3; i++) {
        int bx = MOVE1_X + i * 42;
        uint16_t bg = (i == selected) ? COL_LTBLUE : COL_DARKGRAY;
        draw_filled_rect(bx, MOVE_Y, MOVE_W, MOVE_H, bg);
        draw_rect_border(bx, MOVE_Y, MOVE_W, MOVE_H, COL_WHITE);
        printText(labels[i], bx + 2, MOVE_Y + 2, COL_WHITE, bg);
    }
    // Show God Mode indicator on the move bar if active
    if (god_mode) {
        printText("x10", 110, MOVE_Y + 2, COL_YELLOW, COL_BLACK);
    } else {
        printText("   ", 110, MOVE_Y + 2, COL_BLACK, COL_BLACK);
    }
    printText("<  CONFIRM  >", 2, MOVE_Y + 12, COL_GRAY, COL_BLACK);
}

void draw_char_counters(int player_idx, int ai_idx)
{
    int ay = MSG_Y - 30;
    int py = MSG_Y + 50;

    printText("C:", 0, ay, COL_RED, COL_BLACK);
    for (int i = 0; i < 3; i++) {
        uint16_t col = (i < (3 - ai_idx)) ? COL_RED : COL_DARKGRAY;
        draw_filled_rect(14 + i * 7, ay, 5, 5, col);
        draw_rect_border(14 + i * 7, ay, 5, 5, COL_WHITE);
    }

    printText("P:", 70, py, COL_GREEN, COL_BLACK);
    for (int i = 0; i < 3; i++) {
        uint16_t col = (i < (3 - player_idx)) ? COL_GREEN : COL_DARKGRAY;
        draw_filled_rect(95 + i * 7, py, 5, 5, col);
        draw_rect_border(95 + i * 7, py, 5, 5, COL_WHITE);
    }
}

void draw_scene(int player_hp, int enemy_hp,
                const uint16_t *p_sprite, const uint16_t *e_sprite,
                int player_char_idx, int ai_char_idx)
{
    char buf[14];

    putImage(PLAYER_X, PLAYER_Y, PLAYER_SPR_W, PLAYER_SPR_H, p_sprite, 0, 0);
    putImage(ENEMY_X,  ENEMY_Y,  ENEMY_SPR_W,  ENEMY_SPR_H,  e_sprite, 1, 0);

    draw_hp_bar(PLAYER_HP_BAR_X, PLAYER_HP_BAR_Y, player_hp, 100, hp_color(player_hp, 100));
    draw_hp_bar(ENEMY_HP_BAR_X,  ENEMY_HP_BAR_Y,  enemy_hp,  100, hp_color(enemy_hp,  100));

    buf[0]='H'; buf[1]='P'; buf[2]=':';
    itoa_simple(player_hp, buf+3);
    printText(buf, PLAYER_HP_BAR_X, PLAYER_HP_BAR_Y - 8, COL_WHITE, COL_BLACK);

    buf[0]='H'; buf[1]='P'; buf[2]=':';
    itoa_simple(enemy_hp, buf+3);
    printText(buf, ENEMY_HP_BAR_X, ENEMY_HP_BAR_Y + 7, COL_WHITE, COL_BLACK);

    draw_char_counters(player_char_idx, ai_char_idx);
}

// ─── End Screen ───────────────────────────────────────────────────────────────
void show_end_screen(int player_won)
{
    draw_filled_rect(0, 0, 128, 160, COL_BLACK);

    if (player_won) {
        printTextX2("YOU WIN!", 10, 5, COL_YELLOW, COL_BLACK);
        printText("Your team:", 2, 30, COL_GREEN, COL_BLACK);
        for (int i = 0; i < 3; i++) {
            putImage(2 + i * 40, 40, PLAYER_SPR_W, PLAYER_SPR_H,
                     char_sprites[player_team[i]], 0, 0);
            char tmp[5]; int j;
            for (j = 0; j < 4 && char_names[player_team[i]][j]; j++)
                tmp[j] = char_names[player_team[i]][j];
            tmp[j] = 0;
            printText(tmp, 2 + i * 40, 102, COL_GREEN, COL_BLACK);
        }
        printText("AI team (lost):", 2, 114, COL_RED, COL_BLACK);
        for (int i = 0; i < 3; i++) {
            char tmp[5]; int j;
            for (j = 0; j < 4 && char_names[ai_team[i]][j]; j++)
                tmp[j] = char_names[ai_team[i]][j];
            tmp[j] = 0;
            printText(tmp, 2 + i * 40, 124, COL_RED, COL_BLACK);
        }
    } else {
        printTextX2("YOU LOST!", 8, 5, COL_RED, COL_BLACK);
        printText("AI team:", 2, 30, COL_RED, COL_BLACK);
        for (int i = 0; i < 3; i++) {
            putImage(2 + i * 40, 40, ENEMY_SPR_W, ENEMY_SPR_H,
                     char_sprites[ai_team[i]], 1, 0);
            char tmp[5]; int j;
            for (j = 0; j < 4 && char_names[ai_team[i]][j]; j++)
                tmp[j] = char_names[ai_team[i]][j];
            tmp[j] = 0;
            printText(tmp, 2 + i * 40, 102, COL_RED, COL_BLACK);
        }
        printText("Your team (lost):", 2, 114, COL_GREEN, COL_BLACK);
        for (int i = 0; i < 3; i++) {
            char tmp[5]; int j;
            for (j = 0; j < 4 && char_names[player_team[i]][j]; j++)
                tmp[j] = char_names[player_team[i]][j];
            tmp[j] = 0;
            printText(tmp, 2 + i * 40, 124, COL_GREEN, COL_BLACK);
        }
    }
    printText("Any btn -> Menu", 2, 148, COL_GRAY, COL_BLACK);

    btn_down_just(); btn_up_just(); btn_left_just(); btn_right_just();
    while (!btn_left_just() && !btn_right_just() && !btn_down_just()) {
        delay(50); btn_up_just();
    }
}

// ─── Main ────────────────────────────────────────────────────────────────────
int main(void)
{
    initClock();
    initSysTick();
    setupIO();

    delay(10);
    rng_seed += milliseconds;

game_start:
    // ── Main Menu ──
    // Reset god_mode each time we return to the menu so a new run is clean
    god_mode = 0;
    cheat_pos = 0;

    {
        int menu_select = 0;
        draw_start_screen_full();
        update_start_screen(0, 0);

        while (1) {
            delay(50);
            btn_left_just();

            // ── Cheat code check every frame while in main menu ──
            if (check_cheat_input()) {
                // Sequence matched — show the message then redraw the menu
                show_god_mode_message();
                draw_start_screen_full();
                update_start_screen(menu_select, menu_select);
            }

            if (btn_down_just()) {
                int old = menu_select;
                menu_select = (menu_select + NUM_MENU_ITEMS - 1) % NUM_MENU_ITEMS;
                update_start_screen(old, menu_select);
            }
            if (btn_up_just()) {
                int old = menu_select;
                menu_select = (menu_select + 1) % NUM_MENU_ITEMS;
                update_start_screen(old, menu_select);
            }
            if (btn_right_just()) {
                if (menu_select == 0) break;          // START
                else if (menu_select == 1) {
                    credits();
                    draw_start_screen_full();
                    update_start_screen(menu_select, menu_select);
                }
                // QUIT does nothing
            }
        }
    }

    // ── Character Select ──
    character_select();

    // ── Battle ──
    {
        int player_char_idx = 0;
        int ai_char_idx     = 0;

        int player_hp = 100;
        int enemy_hp  = 100;
        int selected  = 0;
        GameState state = STATE_PLAYER_TURN;

        const uint16_t *p_sprite = char_sprites[player_team[0]];
        const uint16_t *e_sprite = char_sprites[ai_team[0]];
        const Move     *p_moves  = char_moves[player_team[0]];
        const Move     *e_moves  = char_moves[ai_team[0]];

        draw_filled_rect(0, 0, 128, 160, COL_BLACK);
        draw_scene(player_hp, enemy_hp, p_sprite, e_sprite, player_char_idx, ai_char_idx);
        show_message("YOUR TURN", "Choose a move!");
        draw_move_buttons(selected, p_moves);

        while (1)
        {
            delay(50);
            int bl = btn_left_just();
            int br = btn_right_just();
            int bd = btn_down_just();
            btn_up_just();

            // ── Player turn ──
            if (state == STATE_PLAYER_TURN)
            {
                int move_used = -1;
                if (bl) { selected = (selected + 2) % 3; draw_move_buttons(selected, p_moves); }
                else if (br) { selected = (selected + 1) % 3; draw_move_buttons(selected, p_moves); }
                else if (bd) { move_used = selected; }

                if (move_used >= 0) {
                    int dmg = rand_range(p_moves[move_used].dmg_lo, p_moves[move_used].dmg_hi);

                    // ── God Mode: multiply damage by 10 ──
                    if (god_mode) dmg *= 10;

                    enemy_hp -= dmg;
                    if (enemy_hp < 0) enemy_hp = 0;

                    draw_filled_rect(0, 0, 128, 160, COL_BLACK);
                    draw_scene(player_hp, enemy_hp, p_sprite, e_sprite, player_char_idx, ai_char_idx);
                    show_message("YOU attack!", p_moves[move_used].flavor);
                    draw_move_buttons(selected, p_moves);
                    delay(900);

                    if (enemy_hp <= 0) {
                        ai_char_idx++;
                        if (ai_char_idx >= 3) {
                            state = STATE_PLAYER_WIN;
                        } else {
                            enemy_hp  = 100;
                            e_sprite  = char_sprites[ai_team[ai_char_idx]];
                            e_moves   = char_moves[ai_team[ai_char_idx]];

                            draw_filled_rect(0, 0, 128, 160, COL_BLACK);
                            show_message("ENEMY KO'd!", "Next fighter!");
                            draw_filled_rect(40, 40, ENEMY_SPR_W + 10, ENEMY_SPR_H + 10, COL_BLACK);
                            putImage(50, 95, ENEMY_SPR_W, ENEMY_SPR_H, e_sprite, 1, 0);
                            delay(1200);

                            draw_filled_rect(0, 0, 128, 160, COL_BLACK);
                            draw_scene(player_hp, enemy_hp, p_sprite, e_sprite, player_char_idx, ai_char_idx);
                            show_message("YOUR TURN", "Choose a move!");
                            draw_move_buttons(selected, p_moves);
                            state = STATE_PLAYER_TURN;
                        }
                    } else {
                        state = STATE_ENEMY_TURN;
                    }
                }
            }
            // ── Enemy turn ──
            else if (state == STATE_ENEMY_TURN)
            {
                delay(600);
                int ai_move = rand_range(0, 2);
                if (ai_move == 2 && enemy_hp < 50) ai_move = rand_range(0, 1);

                int dmg = rand_range(e_moves[ai_move].dmg_lo, e_moves[ai_move].dmg_hi);
                player_hp -= dmg;
                if (player_hp < 0) player_hp = 0;

                draw_filled_rect(0, 0, 128, 160, COL_BLACK);
                draw_scene(player_hp, enemy_hp, p_sprite, e_sprite, player_char_idx, ai_char_idx);
                show_message("ENEMY attacks!", e_moves[ai_move].flavor);
                draw_move_buttons(selected, p_moves);
                delay(900);

                if (player_hp <= 0) {
                    player_char_idx++;
                    if (player_char_idx >= 3) {
                        state = STATE_ENEMY_WIN;
                    } else {
                        player_hp = 100;
                        p_sprite  = char_sprites[player_team[player_char_idx]];
                        p_moves   = char_moves[player_team[player_char_idx]];
                        selected  = 0;

                        draw_filled_rect(0, 0, 128, 160, COL_BLACK);
                        show_message("YOU were KO'd!", "Next fighter!");
                        putImage(50, 95, PLAYER_SPR_W, PLAYER_SPR_H, p_sprite, 0, 0);
                        delay(1200);

                        draw_filled_rect(0, 0, 128, 160, COL_BLACK);
                        draw_scene(player_hp, enemy_hp, p_sprite, e_sprite, player_char_idx, ai_char_idx);
                        show_message("YOUR TURN", "Choose a move!");
                        draw_move_buttons(selected, p_moves);
                        state = STATE_PLAYER_TURN;
                    }
                } else {
                    state = STATE_PLAYER_TURN;
                    show_message("YOUR TURN", "Choose a move!");
                }
            }
            // ── Win / Lose ──
            else if (state == STATE_PLAYER_WIN || state == STATE_ENEMY_WIN)
            {
                show_end_screen(state == STATE_PLAYER_WIN);
                goto game_start;
            }
        }
    }
    return 0;
}

// ─── Peripheral init ─────────────────────────────────────────────────────────
void initSysTick(void)
{
    SysTick->LOAD = 48000;
    SysTick->CTRL = 7;
    SysTick->VAL  = 10;
    __asm(" cpsie i ");
}
void SysTick_Handler(void)
{
    milliseconds++;
}
void initClock(void)
{
    RCC->CR &= ~(1u<<24);
    while((RCC->CR & (1<<25)));
    FLASH->ACR |= (1<<0);
    FLASH->ACR &= ~((1u<<2) | (1u<<1));
    FLASH->ACR |= (1<<4);
    RCC->CFGR &= ~((1u<<21)|(1u<<20)|(1u<<19)|(1u<<18));
    RCC->CFGR |= ((1<<21)|(1<<19));
    RCC->CFGR |= (1<<14);
    RCC->CR   |= (1<<24);
    RCC->CFGR |= (1<<1);
}
void delay(volatile uint32_t dly)
{
    uint32_t end_time = dly + milliseconds;
    while (milliseconds != end_time)
        __asm(" wfi ");
}
void enablePullUp(GPIO_TypeDef *Port, uint32_t BitNumber)
{
    Port->PUPDR &= ~(3u << BitNumber*2);
    Port->PUPDR |=  (1u << BitNumber*2);
}
void pinMode(GPIO_TypeDef *Port, uint32_t BitNumber, uint32_t Mode)
{
    uint32_t v = Port->MODER;
    v &= ~(3u  << (BitNumber*2));
    v |=  (Mode << (BitNumber*2));
    Port->MODER = v;
}
int isInside(uint16_t x1, uint16_t y1, uint16_t w, uint16_t h, uint16_t px, uint16_t py)
{
    return (px >= x1 && px <= x1+w && py >= y1 && py <= y1+h);
}
void setupIO()
{
    RCC->AHBENR |= (1<<18)|(1<<17);
    display_begin();
    pinMode(GPIOB,4,0); pinMode(GPIOB,5,0);
    pinMode(GPIOA,8,0); pinMode(GPIOA,11,0);
    enablePullUp(GPIOB,4); enablePullUp(GPIOB,5);
    enablePullUp(GPIOA,11); enablePullUp(GPIOA,8);

    // Initialise USART1 for USB-serial keyboard input (PA9=TX, PA10=RX, 9600 baud)
    initUSART1();
}